SELECT prize_tier, SUM(amount) AS total_cash_prize
FROM cash_prizes
GROUP BY prize_tier;

SELECT total_players 
FROM event_statistics
WHERE stat_id = 0;

SELECT event_id, AVG(total_players) AS average_players
FROM events
GROUP BY event_id;

SELECT event_id, total_players
FROM events
ORDER BY total_players DESC;
